-- ============================================================================
-- DEMO SEED — catalogo prodotti per i fornitori (DATI DI TEST, cancellabili).
-- Per ogni profilo FORNITORE genera decine di servizi con foto reali (Pexels),
-- scelti in base al subrole. Idempotente: salta i fornitori che hanno già il
-- catalogo demo (tag 'demo'). Per rimuovere tutto:
--   delete from service_photos where service_id in (select id from services where 'demo' = any(tags));
--   delete from services where 'demo' = any(tags);
-- ============================================================================
create temporary table _seed_img(bucket text primary key, imgs text[], thumbs text[]);
