do $cat$
declare
  s record; v_bucket text; v_cat uuid; v_cats uuid[]; v_imgs text[]; v_thumbs text[];
  v_names text[]; v_unit service_unit; v_lo int; v_hi int;
  v_n int; v_tier int; v_name text; v_price numeric; v_sid uuid;
  v_i1 int; v_i2 int; v_slug text; v_count int := 0; v_nimg int;
  tier_label text[] := array['', ' Premium'];
begin
  for s in select id, coalesce(nullif(trim(subrole),''),'generico') as subrole from public.profiles where role='FORNITORE' loop
    -- idempotenza: salta se ha già il catalogo demo
    if exists (select 1 from public.services where fornitore_id = s.id and 'demo' = any(tags)) then continue; end if;

    v_bucket := case
      when s.subrole ilike '%fotograf%' then 'fotografo'
      when s.subrole ilike '%fior%' then 'fioraio'
      when s.subrole ilike '%cater%' or s.subrole ilike '%chef%' or s.subrole ilike '%cuoc%' or s.subrole ilike '%banqu%' then 'catering'
      when s.subrole ilike '%video%' or s.subrole ilike '%film%' then 'videomaker'
      when s.subrole ilike '%music%' or s.subrole ilike '%dj%' or s.subrole ilike '%band%' then 'musica'
      when s.subrole ilike '%location%' or s.subrole ilike '%venue%' or s.subrole ilike '%villa%' or s.subrole ilike '%dimora%' then 'location'
      when s.subrole ilike '%truc%' or s.subrole ilike '%make%' or s.subrole ilike '%parruc%' or s.subrole ilike '%hair%' or s.subrole ilike '%beauty%' then 'makeup'
      when s.subrole ilike '%plann%' or s.subrole ilike '%organizz%' then 'planner'
      when s.subrole ilike '%allest%' or s.subrole ilike '%scenograf%' or s.subrole ilike '%decor%' or s.subrole ilike '%noleggi%' then 'allestimento'
      when s.subrole ilike '%torta%' or s.subrole ilike '%pasticc%' or s.subrole ilike '%cake%' or s.subrole ilike '%dolc%' or s.subrole ilike '%confett%' then 'torte'
      when s.subrole ilike '%anima%' or s.subrole ilike '%intratten%' or s.subrole ilike '%mago%' or s.subrole ilike '%spettacol%' then 'animazione'
      else 'generico' end;

    select imgs, thumbs into v_imgs, v_thumbs from _seed_img where bucket = v_bucket;
    select names, unit, price_lo, price_hi into v_names, v_unit, v_lo, v_hi from _seed_content where bucket = v_bucket;
    v_nimg := array_length(v_imgs, 1);

    -- categorie del fornitore: quelle col suo subrole, altrimenti creane una
    select array_agg(id) into v_cats from public.service_categories
     where subrole is not null and (subrole = s.subrole or subrole ilike '%'||v_bucket||'%');
    if v_cats is null or array_length(v_cats,1) is null then
      v_slug := v_bucket || '-' || left(s.id::text, 8);
      insert into public.service_categories(name, slug, subrole, is_standard, created_by)
        values (initcap(v_bucket), v_slug, s.subrole, false, s.id)
        on conflict (slug) do update set name = excluded.name
        returning id into v_cat;
      v_cats := array[v_cat];
    end if;

    for v_n in 1 .. coalesce(array_length(v_names,1),0) loop
      for v_tier in 1 .. 2 loop
        v_count := v_count + 1;
        v_name := v_names[v_n] || tier_label[v_tier];
        v_price := greatest(10, round( (v_lo + random()*(v_hi - v_lo)) * (case when v_tier=2 then 1.6 else 1 end) / 10.0 ) * 10);
        v_cat := v_cats[ 1 + (v_count % array_length(v_cats,1)) ];
        v_i1 := 1 + (v_count * 5) % v_nimg;
        v_i2 := 1 + (v_count * 5 + 11) % v_nimg;
        insert into public.services(fornitore_id, category_id, name, description, base_price, unit, is_active, display_order, tags)
          values (s.id, v_cat, v_name,
                  v_name || ' — servizio professionale per il tuo matrimonio, personalizzabile su richiesta.',
                  v_price, v_unit, true, v_count, array[v_bucket, 'matrimonio', 'demo'])
          returning id into v_sid;
        insert into public.service_photos(service_id, original_url, thumbnail_url, sort_order) values
          (v_sid, v_imgs[v_i1], v_thumbs[v_i1], 0),
          (v_sid, v_imgs[v_i2], v_thumbs[v_i2], 1);
      end loop;
    end loop;
  end loop;
  raise notice 'CATALOGO DEMO: % servizi inseriti', v_count;
end$cat$;
